import React from 'react';
import { Link } from 'react-router-dom';
import Button from '../1_atoms/Button';
import './AboutFinalCtaSection.css';

function AboutFinalCtaSection({ title, text, image }) {
  return (
    <section className="about-final-cta">
      <div className="about-final-cta__copy">
        <p className="about-section__eyebrow">Финальный акцент</p>
        <h2>{title}</h2>
        <p>{text}</p>
        <div className="about-final-cta__actions">
          <Link to="/account">
            <Button>Открыть игру</Button>
          </Link>
          <Link to="/blog">
            <Button variant="secondary">Посмотреть блог</Button>
          </Link>
        </div>
      </div>
      <div className="about-final-cta__visual">
        <img src={image} alt={title} />
      </div>
    </section>
  );
}

export default AboutFinalCtaSection;
